const Alert = ({ type = 'error', message }) => {
  if (!message) return null;
  return (
    <div className={`alert alert-${type}`}>
      <span>{type === 'error' ? '⚠️' : '✅'}</span>
      {message}
    </div>
  );
};

export default Alert;
